import { localInputToISOWithOffset, utcToLocalInputValue } from '@linm-soft-org/linm-web-common-components';
import type {
  BankInternalTransferDto,
  CreateBankInternalTransferDto,
} from '../../../../../services/kt/models';

export type BankTransferFormState = CreateBankInternalTransferDto & {
  fromAccountCode?: string;
  toAccountCode?: string;
  legacyId?: string;
};

export const todayLocalDateInput = () => new Date().toISOString().slice(0, 10);

export const defaultBankTransferFormState = (): BankTransferFormState => ({
  voucherDate: todayLocalDateInput(),
  transferReasonCode: 'CTNB',
  fromPaymentChannelCode: '',
  toPaymentChannelCode: '',
  amount: 0,
  description: '',
  counterpartyName: '',
  counterpartyBankAccount: '',
  processingLevel: '',
  fromAccountCode: '',
  toAccountCode: '',
  legacyId: '',
});

export const mapDtoToBankTransferForm = (dto: BankInternalTransferDto): BankTransferFormState => ({
  voucherDate: utcToLocalInputValue(dto.voucherDate).slice(0, 10),
  transferReasonCode: dto.transferReasonCode || 'CTNB',
  fromPaymentChannelCode: dto.fromPaymentChannelCode || '',
  toPaymentChannelCode: dto.toPaymentChannelCode || '',
  amount: Number(dto.amount) || 0,
  description: dto.description || '',
  counterpartyName: dto.counterpartyName || '',
  counterpartyBankAccount: dto.counterpartyBankAccount || '',
  processingLevel: dto.processingLevel || '',
  fromAccountCode: dto.fromAccountCode || '',
  toAccountCode: dto.toAccountCode || '',
  legacyId: dto.legacyId || '',
});

export const buildBankTransferSavePayload = (
  form: BankTransferFormState,
): CreateBankInternalTransferDto => ({
  voucherDate: localInputToISOWithOffset(form.voucherDate),
  transferReasonCode: form.transferReasonCode.trim(),
  fromPaymentChannelCode: form.fromPaymentChannelCode.trim(),
  toPaymentChannelCode: form.toPaymentChannelCode.trim(),
  amount: Number(form.amount) || 0,
  description: form.description?.trim() || undefined,
  counterpartyName: form.counterpartyName?.trim() || undefined,
  counterpartyBankAccount: form.counterpartyBankAccount?.trim() || undefined,
  legacyId: form.legacyId?.trim() || undefined,
  processingLevel: form.processingLevel.trim(),
});

export const serializeBankTransferSnapshot = (form: BankTransferFormState) =>
  JSON.stringify(buildBankTransferSavePayload(form));
